// src/modals/PartsModal.ts
var import_obsidian7 = require("obsidian");
var PartsModal = class extends import_obsidian7.Modal {
  constructor(app, onSubmit) {
    super(app);
    this.parts = [{ name: "", count: 1 }];
    this.onSubmit = onSubmit;
  }
  onOpen() {
    const { contentEl } = this;
    contentEl.empty();
    contentEl.addClass("parts-modal");
    contentEl.createEl("h3", { text: "添加更换备件" });
    this.parentEl = contentEl.createDiv({ cls: "parts-form" });
    this.renderParts();
    new import_obsidian7.Setting(contentEl).addButton(
      (b) => b.setButtonText("添加零件").onClick(() => {
        this.parts.push({ name: "", count: 1 });
        this.renderParts();
      })
    );
    new import_obsidian7.Setting(contentEl).addButton(
      (b) => b.setButtonText("取消").onClick(() => this.close())
    ).addButton(
      (b) => b.setButtonText("确认").setCta().onClick(() => {
        const valid = this.parts.filter((p) => p.name.trim());
        this.close();
        this.onSubmit(valid);
      })
    );
  }
  renderParts() {
    if (!this.parentEl) return;
    const pe = this.parentEl;
    pe.empty();
    this.parts.forEach((part, idx) => {
      const row = pe.createDiv({ cls: "parts-row" });
      row.createEl("input", {
        type: "text",
        placeholder: "零件名称",
        value: part.name
      }).addEventListener("input", (e) => {
        part.name = e.target.value;
      });
      row.createEl("input", {
        type: "number",
        placeholder: "数量",
        value: String(part.count),
        attr: { min: "1", style: "width:80px;" }
      }).addEventListener("input", (e) => {
        const n = parseInt(e.target.value, 10);
        part.count = isNaN(n) || n < 1 ? 1 : n;
      });
      if (this.parts.length > 1) {
        const delBtn = row.createEl("button", { text: "×", attr: { style: "padding:2px 8px;cursor:pointer;" } });
        delBtn.addEventListener("click", () => {
          this.parts.splice(idx, 1);
          this.renderParts();
        });
      }
    });
  }
  onClose() {
    const { contentEl } = this;
    contentEl.empty();
  }
};

